INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "私たちはみんな、同じ食卓を囲む\n家族なんだから。\n大事な家族の特別な日を\nお祝いするのは、当然のことよ。", 11, 0, 8614066, 1, 10, 0.5, 106411, 1, 8614);
