INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "私としてはカルミナだけでお祝いしても\nよかったんですけどね。\n騎士さんがどうしても一緒に\nお祝いしたいと言うので……", 11, 0, 10914063, 1, 10, 0.5, 105411, 1, 10914);
