INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "誕生、日……？\n私のですか？\nなぜそんなことを\n覚えているのですか？", 11, 0, 16614068, 1, 10, 0.5, 102711, 1, 16614);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 16614069, "", "", "", 0, "", 16614);
