INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "………………そう、ですか。\nそれならありがたく\nいただくことにしましょう。", 11, 0, 16614078, 1, 10, 0.5, 102711, 1, 16614);
