INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "あれ、このケーキって……？\nもしかして、ミソギのお誕生日、\nお祝いしてくれるの！？", 11, 0, 17714057, 1, 10, 0.5, 100411, 1, 17714);
