INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "やったー、ありがとー！\nそれにしても、おっきい～……\n運ぶの、大変じゃなかった？", 11, 0, 17714067, 1, 10, 0.5, 100411, 1, 17714);
