INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ええっと……なんていうか。\nクリスティーナがアタシのために\nケーキを用意してくれるなんてな。\nどういう風の吹き回しだ？", 11, 0, 17824050, 1, 10, 0.5, 106111, 1, 17824);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 17824051, "", "", "", 0, "", 17824);
