INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_smile", 3, "", 17824058, "", 1, "", 106111, "", 17824);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_17824_002", 21, "", 17824059, "", 0, "", "vo_wac_17824", 0, 17824);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "二人とも……本当に、ありがとな！\nそれならアタシも大悪党らしく、\n豪快に、ド派手に、ワガママ放題\n楽しんでやる！", 11, 0, 17824060, 1, 10, 0.5, 106111, 1, 17824);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 17824061, "", "", "", 0, "", 17824);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_doya", 3, "", 17824062, "", 1, "", 106111, "", 17824);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_17824_003", 21, "", 17824063, "", 0, "", "vo_wac_17824", 0, 17824);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "それでいつか、今日のことを\nオクトーのやつに自慢するんだ！\nどうだ、すっごーく悪いだろ！\nきっと悔しがるぞ♪", 11, 0, 17824064, 1, 10, 0.5, 106111, 1, 17824);
