INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "私のために、ケーキで\nお祝いしてくれるなんて……\nみんなの先生でいられて、\n本当によかったって思うわ♪", 11, 0, 18114058, 1, 10, 0.5, 101811, 1, 18114);
