INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "イオちゃん、大げさだよ～\nでも、喜んでもらえたなら、\n手作りしてよかったかも♪", 11, 0, 18114063, 1, 10, 0.5, 105011, 1, 18114);
