INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ヒデサイにも買い出しとか\n手伝ってもらったしー\nみんなでお祝いする誕生日って、\nそれだけでエモいっしょ♪", 11, 0, 18114068, 1, 10, 0.5, 101611, 1, 18114);
