INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_eriko_talk_sad", 3, "", 18814094, "", 1, "", 102711, "", 18814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_18814_005", 21, "", 18814095, "", 0, "", "vo_wac_18814", 0, 18814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ところで。\nどうしてナナカさんが欲しがっている\n限定品を、あなた様が正確に把握して\nいらっしゃったのでしょう……？", 11, 0, 18814096, 1, 10, 0.5, 102711, 1, 18814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 18814097, "", "", "", 0, "", 18814);
