INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "それは～、えーっと……\nやばい、目が笑ってないでござる。\n定期巡回のことを話したら、\n確実に斧でケーキ入刀される～！？", 11, 0, 18814101, 1, 10, 0.5, 101311, 1, 18814);
