INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ちゃんと、私たちの気持ちが\n伝わるような贈り物にしたかったんだ。\nだから、味の方はあまり期待しないで\nくれるかな？", 11, 0, 19414068, 1, 10, 0.5, 100311, 1, 19414);
