INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "このおいしそうなケーキは……ハッ！？\nワタシの命を狙う、アクダイカンの\n仕組んだトラップでショウか？", 11, 0, 19814071, 1, 10, 0.5, 103011, 1, 19814);
