INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ちなみに、このケーキは美しいボクと\nギルドの仲間たち、それといつもの\nこの人で選んだんだ。主にボクの\n顔を思い浮かべつつ味わってよね♪", 11, 0, 19814096, 1, 10, 0.5, 100811, 1, 19814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 19814097, "", "", "", 0, "", 19814);
