INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "なんと、ショーグンまで！？\nみなさん、アリガトウゴザイマシタ！\nこの喜び、忍法で表現シマスよ～？\nシュバ、シュババ、シュバババ～♪", 11, 0, 19814101, 1, 10, 0.5, 103011, 1, 19814);
