INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "すぅ～っ……\nお誕生日おめでとうございます、\nキャルちゃ～ん！", 11, 0, 20014068, 1, 10, 0.5, 105811, 1, 20014);
