INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "もちろん、キャルさまのでございます。\n【美食殿】全員で心を込めて\nご用意させていただいた、特製の\n手作りケーキとなっております。", 11, 0, 20014080, 1, 10, 0.5, 105911, 1, 20014);
