INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "そっか……えへへ……♪\nなら、最初っからそう言いなさいよ。\nそしたら素直にお礼だって言えるし。\n……うん、ありがとう♪", 11, 0, 20014085, 1, 10, 0.5, 106011, 1, 20014);
