INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "あの、キャル……\n喜んでるところ、悪いんだけど……\nその、材料の方は、魔物の……\nペコリーヌさんが、どうしてもって……", 11, 0, 20014090, 1, 10, 0.5, 106411, 1, 20014);
