INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "きゃん！？　何かしらこのケーキ！\nえっ、えっ、もしかして今日って、\n誰かの誕生日だったりしました？", 11, 0, 21314055, 1, 10, 0.5, 110911, 1, 21314);
