INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "えへへ、どーもどーも。\nいや素直に嬉しいですよね、\nわざわざこんな準備までしてもらって。\nその気持ちだけでホント幸せです！", 11, 0, 21314065, 1, 10, 0.5, 110911, 1, 21314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 21314066, "", "", "", 0, "", 21314);
