INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ま、それはそれとしてなんですけど、\n世界の美少女ちえるんへの誕プレは\n本日より３６５日受け付けてまっす！\nちぇる～ん☆", 11, 0, 21314069, 1, 10, 0.5, 110911, 1, 21314);
