INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "はぁ。誕生日など歳を重ねるだけの\nつまらぬ行事ではありませんこと？\nバースデーケーキでお祝いと言われても\n喜ぶ気持ちにはそうそう……", 11, 0, 21714048, 1, 10, 0.5, 118011, 1, 21714);
