INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "今日は、本当にみんなありがとう。\nあたしの誕生日のために、こんなに\n素敵なケーキを用意してくれるなんてね♪", 11, 0, 23214063, 1, 10, 0.5, 102811, 1, 23214);
