INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "お誕生日おめでとう、ママ・サレン♪\nいつも、私たちのために、\n一生懸命お仕事頑張って\nくれてるから……", 11, 0, 23214068, 1, 10, 0.5, 102111, 1, 23214);
