INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "頑張って手作りしたんだよ？\nできあがる頃には、いろんな意味で\nスズメはボロボロになってたけど。", 11, 0, 23214073, 1, 10, 0.5, 102311, 1, 23214);
