INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "アヤネちゃん、それは内緒に……！\nうぅ、お料理中も結構ドジしちゃって。\nお嬢様の大切な日の準備なのに、\nすみません……", 11, 0, 23214078, 1, 10, 0.5, 102511, 1, 23214);
