INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_normal", 3, "", 23814082, "", 1, "", 100811, "", 23814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_23814_003", 21, "", 23814083, "", 0, "", "vo_wac_23814", 0, 23814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "どうもありがとう♪\nそれにしても素晴らしいケーキだね、\nボクのために用意してくれたの？", 11, 0, 23814084, 1, 10, 0.5, 100811, 1, 23814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 23814085, "", "", "", 0, "", 23814);
