INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_smile", 3, "", 23814087, "", 1, "", 105511, "", 23814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_23814_004", 21, "", 23814088, "", 0, "", "vo_wac_23814", 0, 23814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "はい♪　喜んでもらえるように、\nお店の人に頼んでしっかり\n見た目にもこだわってもらいました。", 11, 0, 23814089, 1, 10, 0.5, 105511, 1, 23814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 23814090, "", "", "", 0, "", 23814);
