INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_23814_005", 21, "", 23814093, "", 0, "", "vo_wac_23814", 0, 23814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ちなみにご予算がかかったので、\nショーグンにもルピを出してもらい\nマシタ！　感謝の極みデス！", 11, 0, 23814094, 1, 10, 0.5, 103011, 1, 23814);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 23814095, "", "", "", 0, "", 23814);
