INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "そうだったんだ……感謝しなきゃね♪\nお礼に今日は、好きな角度から\n心ゆくまで、ボクのかわいい顔を\n堪能してもらってかまわないよ♪", 11, 0, 23814099, 1, 10, 0.5, 100811, 1, 23814);
