INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_25214_001", 21, "", 25214060, "", 0, "", "vo_wac_25214", 0, 25214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ちょっと待ってくださいお姉ちゃん！\n私たちも手伝ってますよ！\nココとか！　ココもです！", 11, 0, 25214061, 1, 10, 0.5, 101111, 1, 25214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 25214062, "", "", "", 0, "", 25214);
