INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "あー！　お姉ちゃん！\n誕生日だからってずるいですよ！", 11, 0, 25214075, 1, 10, 0.5, 101111, 1, 25214);
