INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "当然だな☆\nこのクリスティーナが全て段取りを\nつけたのだ、満足できないはずがない！", 11, 0, 25314075, 1, 10, 0.5, 107111, 1, 25314);
