INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_smile", 3, "", 26214066, "", 1, "", 103311, "", 26214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_26214_001", 21, "", 26214067, "", 0, "", "vo_wac_26214", 0, 26214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "そうだべ！\n誕生日おめでとう、シオシオ！\nこのケーキはシオシオの好きな\n牧場特製の食材も使って作ったべや！", 11, 0, 26214068, 1, 10, 0.5, 103311, 1, 26214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 26214069, "", "", "", 0, "", 26214);
