INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "リンちゃん……それにみんな、\n本当にありがとうございます。\nあなたも来てくれるなんて、\n私、とってもうれしいです。", 11, 0, 26214083, 1, 10, 0.5, 103811, 1, 26214);
