INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_26224_003", 21, "", 26224077, "", 0, "", "vo_wac_26224", 0, 26224);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "おめでとう、カスミ！\nていうか、姫さんほんとに踊るのか？\nだったら、カスミも一緒に踊ろうぜ！\nみんなでやった方が楽しいからな♪", 11, 0, 26224078, 1, 10, 0.5, 104311, 1, 26224);
