INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "そ、そんなに急かさなくても……！\nというか助手くんも来てくれたのかい？\nわざわざ祝いに来てくれるなんて、\nその……うん、すごく、うれしいよ。", 11, 0, 26224083, 1, 10, 0.5, 101411, 1, 26224);
