INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "なにを水臭いことを\nおっしゃるんですの、ミフユさん！\n私たちは天下御免の\n【メルクリウス財団】ですのよ？", 11, 0, 27014068, 1, 10, 0.5, 103211, 1, 27014);
