INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "生まれし日、時は違えど！\nいっぱいお金を稼いで世の中を\nよくしようという志は同じにゃ！", 11, 0, 27014073, 1, 10, 0.5, 104611, 1, 27014);
