INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "だから仲間のお祝いは、\nケーキと麦しゅわでパーッと、\n楽しく盛り上げなきゃね♪\n……ひっく。", 11, 0, 27014078, 1, 10, 0.5, 103411, 1, 27014);
