INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "うっ……クリスティーナおばさんは\n怖いけど……みんな、ありがとうッス！\nそれにあんたも祝ってくれるなんて、\n自分はすごく幸せ者ッスよー！", 11, 0, 28414083, 1, 10, 0.5, 100511, 1, 28414);
