INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "これって私の誕生日ケーキだよね！？\nみんなで用意してくれたの！？\nもしかして愛情たっぷりの手作り！？\nかわいー！　美味しそうー！", 11, 0, 29014058, 1, 10, 0.5, 109211, 1, 29014);
