INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ふふっ、喜んでもらえて良かった……\nアンのそんな顔が見たくて……\nがんばってみたの。\n……ね、ルゥ？", 11, 0, 29014063, 1, 10, 0.5, 109411, 1, 29014);
