INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "そうですよー！\nルゥは今回も大活躍だったんですよ！\n材料をぐるぐるかき混ぜたり、\nかき混ぜたり、かき混ぜたりしました！", 11, 0, 29014068, 1, 10, 0.5, 109311, 1, 29014);
