INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "そうよね～、迷惑かけまくりよね～？\nお腹が空いたらすぐ泣くし、目についた\n物はなんでも口に入れちゃうし。", 11, 0, 30314080, 1, 10, 0.5, 106011, 1, 30314);
