INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ハッピー☆バースデー☆ハツネちゃん！\nおっきなケーキまでもらっちゃって、\n最高の誕生日だよ～きらーんっ☆", 11, 0, 31314058, 1, 10, 0.5, 101211, 1, 31314);
