INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "うん、おめでとう～♪\nみんなでケーキも用意したから、\n楽しくお祝いしましょうね～\nほら、アオイちゃんも。", 11, 0, 31314063, 1, 10, 0.5, 101511, 1, 31314);
