INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "えっとさー、その～……\n普段あんまりお仕事してないのに、\nこんな大げさにお祝いされると\n気まずいっていうか～……", 11, 0, 32114065, 1, 10, 0.5, 102611, 1, 32114);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 32114066, "", "", "", 0, "", 32114);
