INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_wish", 3, "", 32114073, "", 1, "", 103811, "", 32114);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_32114_002", 21, "", 32114074, "", 0, "", "vo_wac_32114", 0, 32114);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "変に遠慮しないでくださいね？\nみんな、リンちゃんのことを\nお祝いしたくて、張り切って\n準備したんですから。", 11, 0, 32114075, 1, 10, 0.5, 103811, 1, 32114);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 32114076, "", "", "", 0, "", 32114);
