INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_smile", 3, "", 32114078, "", 1, "", 102611, "", 32114);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_32114_003", 21, "", 32114079, "", 0, "", "vo_wac_32114", 0, 32114);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "うぅ……そうだったんだね……\nここまでしてもらったんだから、\nあたしも心を入れ替えて、\n来年からはお仕事がんばるよ！", 11, 0, 32114080, 1, 10, 0.5, 102611, 1, 32114);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 32114081, "", "", "", 0, "", 32114);
