INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_32114_004", 21, "", 32114084, "", 0, "", "vo_wac_32114", 0, 32114);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ほ、本当だべか！？\n苦労して誕生日パーティーを用意した\n甲斐があったべさ～……って、ん？\nちょっと待つべ、来年？", 11, 0, 32114085, 1, 10, 0.5, 103311, 1, 32114);
