INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "そう、来年から～\nというわけで今年も一年、\nぐうたらライフで平常運転\nしていくんで、よろしく～", 11, 0, 32114092, 1, 10, 0.5, 102611, 1, 32114);
