INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "誕生日のお祝い、ありがとね！\nアタシももう、立派なレディの\n仲間入りって感じかしら♪", 11, 0, 32314058, 1, 10, 0.5, 105011, 1, 32314);
