INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_sad", 3, "", 32314066, "", 1, "", 105011, "", 32314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_32314_002", 21, "", 32314067, "", 0, "", "vo_wac_32314", 0, 32314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "えっ！？\nそ、それは、その～……\n大人のレディ向けジュースとかないの？\n苦いのも、別にダメじゃないけど！", 11, 0, 32314068, 1, 10, 0.5, 105011, 1, 32314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 32314069, "", "", "", 0, "", 32314);
