INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_smile", 3, "", 32314071, "", 1, "", 101811, "", 32314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_32314_003", 21, "", 32314072, "", 0, "", "vo_wac_32314", 0, 32314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ふふっ、ちゃんとあるわよ♪\nこうやってオシャレなグラスに\nぶどうジュースを注げば……\nほら、大人っぽいでしょう？", 11, 0, 32314073, 1, 10, 0.5, 101811, 1, 32314);
