INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "今日は、こんな素敵な誕生日ケーキを\n用意してくれてありがとう。\nその……すまない、なんだか\n照れくさくて、上手く話せないな。", 11, 0, 33214058, 1, 10, 0.5, 100311, 1, 33214);
