INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "大丈夫だよ。\n今のレイちゃんの顔を見たら、\nすごく喜んでくれてるって\nちゃんと分かるから♪", 11, 0, 33214063, 1, 10, 0.5, 100211, 1, 33214);
