INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "顔を真っ赤にしてるレイさんなんて\nなかなか見られないからね～\nほらほら、騎士くんもしっかり\n目に焼き付けておきなよ♪", 11, 0, 33214068, 1, 10, 0.5, 100111, 1, 33214);
