INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "お返しって考えたらどうでしょう？\nほら、今回も騎士さんにケーキの\n用意とか手伝ってもらいましたし。\nアイドルらしいお礼になりませんか？", 11, 0, 34414068, 1, 10, 0.5, 105411, 1, 34414);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 34414069, "", "", "", 0, "", 34414);
