INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_34414_003", 21, "", 34414072, "", 0, "", "vo_wac_34414", 0, 34414);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "ツムギ、いいこと言うじゃない♪\nそれじゃあ感謝の気持ちを込めて……\nキミのためのバースデーライブ、\n開催しちゃおうかな♪", 11, 0, 34414073, 1, 10, 0.5, 102911, 1, 34414);
