INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_35314_000", 21, "", 35314057, "", 0, "", "vo_wac_35314", 0, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "えっと、今日はありがとう……！\nでもこんな立派なお誕生日ケーキ、\n本当にもらってもいいの？\nお金とか、大丈夫だった……？", 11, 0, 35314058, 1, 10, 0.5, 103611, 1, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 35314059, "", "", "", 0, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_idle_wish", 3, "", 35314060, "", 1, "", 103611, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_normal", 3, "", 35314061, "", 1, "", 100411, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_35314_001", 21, "", 35314062, "", 0, "", "vo_wac_35314", 0, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "まじめだな～、キョウカは。\nミソギがケーキをもらったときは、\nまずどの飾りから食べようかなーって\n思ってたくらいなのに。", 11, 0, 35314063, 1, 10, 0.5, 100411, 1, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 35314064, "", "", "", 0, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_idle_normal", 3, "", 35314065, "", 1, "", 100411, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_sad", 3, "", 35314066, "", 1, "", 103611, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_35314_002", 21, "", 35314067, "", 0, "", "vo_wac_35314", 0, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "でも、お返しとかあるでしょ？\nちゃんとみんなに、同じくらい\n立派なお礼を用意しないと！", 11, 0, 35314068, 1, 10, 0.5, 103611, 1, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 35314069, "", "", "", 0, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_idle_sad", 3, "", 35314070, "", 1, "", 103611, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_smile", 3, "", 35314071, "", 1, "", 102011, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_35314_003", 21, "", 35314072, "", 0, "", "vo_wac_35314", 0, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "大丈夫だよ、キョウカちゃん。\nミミたちも、おにいちゃんも、\nキョウカちゃんがよろこんでくれたら、\nそれだけでうれしいよ♪", 11, 0, 35314073, 1, 10, 0.5, 102011, 1, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 35314074, "", "", "", 0, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_idle_smile", 3, "", 35314075, "", 1, "", 102011, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_wish", 3, "", 35314076, "", 1, "", 103611, "", 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_35314_004", 21, "", 35314077, "", 0, "", "vo_wac_35314", 0, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "……うん、わかった。\nまた誰かのお誕生日が来たら、\nこうやってお祝いしようね♪\nそれが一番のお返しになると思うから。", 11, 0, 35314078, 1, 10, 0.5, 103611, 1, 35314);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 35314079, "", "", "", 0, "", 35314);
