INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "私がフルーツをもりつけたんだ。\nあと、この人の提案で\n味も甘めにしておいたからね。\nルゥが好きかなって……", 11, 0, 35514068, 1, 10, 0.5, 109411, 1, 35514);
