INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_38214_001", 21, "", 38214069, "", 0, "", "vo_wac_38214", 0, 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "マヒルさん、どうしました……？\nもしかして、誕生日ケーキに\n変なところでも……？", 11, 0, 38214070, 1, 10, 0.5, 103811, 1, 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 38214071, "", "", "", 0, "", 38214);
