INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_smile", 3, "", 38214078, "", 1, "", 102611, "", 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_38214_003", 21, "", 38214079, "", 0, "", "vo_wac_38214", 0, 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "いやいや、紛らわしすぎるから。\n普通のお礼で十分でしょ、\n深刻そうなオーラ醸さないでよね？", 11, 0, 38214080, 1, 10, 0.5, 102611, 1, 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 38214081, "", "", "", 0, "", 38214);
