INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_smile", 3, "", 38214083, "", 1, "", 105211, "", 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_38214_004", 21, "", 38214084, "", 0, "", "vo_wac_38214", 0, 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "そうそう。\n難しい顔するより、\nみんなで楽しくおいしくケーキを\n食べましょう♪", 11, 0, 38214085, 1, 10, 0.5, 105211, 1, 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 38214086, "", "", "", 0, "", 38214);
