INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0.2, "wac_birthday_talk_smile", 3, "", 38214088, "", 1, "", 103311, "", 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "vo_wac_38214_005", 21, "", 38214089, "", 0, "", "vo_wac_38214", 0, 38214);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "いや、みんなにきちんと\nギャグでお返ししてぇべ！　……あ！\nバースデーは、とばーすでー！\nさ、今年も飛ばしてくど！", 11, 0, 38214090, 1, 10, 0.5, 103311, 1, 38214);
