INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "クスクス……安心してください。\n少なくともロウソクの数よりは、\nずっと若々しく見えていますわ……♪", 11, 0, 38614100, 1, 10, 0.5, 102711, 1, 38614);
