INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "いろんなことがあったわよね……\n飛空艇を沈め、学院を破壊し、\n何度も破産の危機を迎えながらも……", 11, 0, 39114073, 1, 10, 0.5, 104811, 1, 39114);
