INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "麦しゅわの助けも借りながら、\nみんなで協力して、\n全部乗り越えることができたもの！", 11, 0, 39114078, 1, 10, 0.5, 103411, 1, 39114);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES ("", "", 91, "", 39114079, "", "", "", 0, "", 39114);
