INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "麦しゅわで心の痛みを和らげていたのは\nユカリさんだけですが、確かに、\n私たちは戦友と呼べるほどに\n深い絆で結ばれたのかもしれません。", 11, 0, 39114083, 1, 10, 0.5, 103211, 1, 39114);
