INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "よ、喜んでいただけたのは\nうれしいのですが……ユカリさん、\n様子がおかしくありませんこと？", 11, 0, 39514068, 1, 10, 0.5, 103211, 1, 39514);
