INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (0, "さっきまでお礼のスピーチを\n考えてたらしいんだけど、\nいいアイデアが浮かばないからって、\n麦しゅわを飲んじゃったのよね……", 11, 0, 39514073, 1, 10, 0.5, 104811, 1, 39514);
